static bool player_selected = true;
static bool enemy_selected = false;

if (ImGui::Begin("الموارد")) {
 if (ImGui::Selectable("Player.mesh", &player_selected)) {
 enemy_selected = false;
 }
 if (ImGui::Selectable("Enemy.mesh", &enemy_selected)) {
 player_selected = false;
 }

 ImGui::Text("العنصر النشط: %s", player_selected ? "Player.mesh" : "Enemy.mesh");
}
ImGui::End();
